17	#define COLORTRANSPARENT(color) ((color & 0xff000000) == 0)
18	#define COLORNOTTRANSPARENT(color) ((color & 0xff000000) != 0)
19	#define TRANS_COLOR 0x00000000
20	#define GDPCOLOR_FROM_COLORREF(color)                                \
21	  Gdiplus::Color::MakeARGB(((color >> 24) & 0xff), GetRValue(color), \
22	                           GetGValue(color), GetBValue(color))
23	#define HALF_ALPHA_COLOR(color) \
24	  ((((color & 0xff000000) >> 25) & 0xff) << 24) | (color & 0x00ffffff)
