28	template <class t0, class t1, class t2>
29	inline void LoadIconNecessary(t0& a, t1& b, t2& c, int d) {
30	  if (a == b)
31	    return;
32	  a = b;
33	  if (b.empty())
34	    c.LoadIconW(d, STATUS_ICON_SIZE, STATUS_ICON_SIZE, LR_DEFAULTCOLOR);
35	  else
36	    c = (HICON)LoadImage(NULL, b.c_str(), IMAGE_ICON, STATUS_ICON_SIZE,
37	                         STATUS_ICON_SIZE, LR_LOADFROMFILE);
38	}
39	
40	static inline void ReconfigRoundInfo(IsToRoundStruct& rd,
41	                                     const int& i,
42	                                     const int& m_candidateCount) {
43	  if (i == 0 && m_candidateCount > 1) {
44	    std::swap(rd.IsTopLeftNeedToRound, rd.IsBottomLeftNeedToRound);
45	    std::swap(rd.IsTopRightNeedToRound, rd.IsBottomRightNeedToRound);
46	  }
47	  if (i == m_candidateCount - 1) {
48	    std::swap(rd.IsTopLeftNeedToRound, rd.IsBottomLeftNeedToRound);
49	    std::swap(rd.IsTopRightNeedToRound, rd.IsBottomRightNeedToRound);
50	  }
51	}
52	
53	WeaselPanel::WeaselPanel(weasel::UI& ui)
54	    : m_layout(NULL),
55	      m_ctx(ui.ctx()),
56	      m_octx(ui.octx()),
57	      m_status(ui.status()),
58	      m_in_server(ui.InServer()),
59	      m_style(ui.style()),
60	      m_ostyle(ui.ostyle()),
61	      m_candidateCount(0),
62	      m_lastCandidateCount(0),
63	      m_current_zhung_icon(),
64	      m_inputPos(CRect()),
65	      m_sticky(false),
66	      dpi(96),
67	      hide_candidates(false),
68	      pDWR(ui.pdwr()),
69	      _UICallback(ui.uiCallback()),
70	      _m_gdiplusToken(0) {
71	  m_iconDisabled.LoadIconW(IDI_RELOAD, STATUS_ICON_SIZE, STATUS_ICON_SIZE,
72	                           LR_DEFAULTCOLOR);
73	  m_iconEnabled.LoadIconW(IDI_ZH, STATUS_ICON_SIZE, STATUS_ICON_SIZE,
74	                          LR_DEFAULTCOLOR);
75	  m_iconAlpha.LoadIconW(IDI_EN, STATUS_ICON_SIZE, STATUS_ICON_SIZE,
76	                        LR_DEFAULTCOLOR);
77	  m_iconFull.LoadIconW(IDI_FULL_SHAPE, STATUS_ICON_SIZE, STATUS_ICON_SIZE,
78	                       LR_DEFAULTCOLOR);
79	  m_iconHalf.LoadIconW(IDI_HALF_SHAPE, STATUS_ICON_SIZE, STATUS_ICON_SIZE,
80	                       LR_DEFAULTCOLOR);
81	  // for gdi+ drawings, initialization
82	  GdiplusStartup(&_m_gdiplusToken, &_m_gdiplusStartupInput, NULL);
83	
84	  HMONITOR hMonitor = MonitorFromRect(m_inputPos, MONITOR_DEFAULTTONEAREST);
85	  UINT dpiX = 96, dpiY = 96;
86	  if (hMonitor) {
87	    GetDpiForMonitor(hMonitor, MDT_EFFECTIVE_DPI, &dpiX, &dpiY);
88	    m_hMonitor = hMonitor;
89	  }
90	  dpi = dpiX;
91	  _InitFontRes();
92	  m_ostyle = m_style;
93	}
94	
95	WeaselPanel::~WeaselPanel() {
96	  Gdiplus::GdiplusShutdown(_m_gdiplusToken);
97	  delete m_layout;
98	  m_layout = NULL;
99	  // pDWR.reset();
100	}
101	
102	void WeaselPanel::_ResizeWindow() {
103	  CDCHandle dc = GetDC();
104	  CSize m_size = m_layout->GetContentSize();
105	  SetWindowPos(NULL, 0, 0, m_size.cx, m_size.cy,
106	               SWP_NOACTIVATE | SWP_NOMOVE | SWP_NOZORDER | SWP_NOREDRAW);
107	  ReleaseDC(dc);
108	}
109	
110	void WeaselPanel::_CreateLayout() {
111	  if (m_layout != NULL)
112	    delete m_layout;
113	
114	  Layout* layout = NULL;
115	  if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT) {
116	    layout = new VHorizontalLayout(m_style, m_ctx, m_status, pDWR);
117	  } else {
118	    if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL ||
119	        m_style.layout_type == UIStyle::LAYOUT_VERTICAL_FULLSCREEN) {
120	      layout = new VerticalLayout(m_style, m_ctx, m_status, pDWR);
121	    } else if (m_style.layout_type == UIStyle::LAYOUT_HORIZONTAL ||
122	               m_style.layout_type == UIStyle::LAYOUT_HORIZONTAL_FULLSCREEN) {
123	      layout = new HorizontalLayout(m_style, m_ctx, m_status, pDWR);
124	    }
125	
126	    if (IS_FULLSCREENLAYOUT(m_style)) {
127	      layout = new FullScreenLayout(m_style, m_ctx, m_status, m_inputPos,
128	                                    layout, pDWR);
129	    }
130	  }
131	  m_layout = layout;
132	}
133	
134	// 更新界面
135	void WeaselPanel::Refresh() {
136	  bool should_show_icon =
137	      (m_status.ascii_mode || !m_status.composing || !m_ctx.aux.empty());
138	  m_candidateCount = min(m_ctx.cinfo.candies.size(), MAX_CANDIDATES_COUNT);
139	  // When the candidate window changes from having content to having no content,
140	  // reset the sticky state
141	  if (m_lastCandidateCount > 0 && m_candidateCount == 0) {
142	    m_sticky = false;
143	  }
144	  m_lastCandidateCount = m_candidateCount;
145	  // check if to hide candidates window
146	  // show tips status, two kind of situation: 1) only aux strings, don't care
147	  // icon status; 2)only icon(ascii mode switching)
148	  bool show_tips =
149	      m_in_server &&
150	      ((!m_ctx.aux.empty() && m_ctx.cinfo.empty() && m_ctx.preedit.empty()) ||
151	       (m_ctx.empty() && should_show_icon));
152	  // show schema menu status: schema_id == L".default"
153	  bool show_schema_menu = m_status.schema_id == L".default";
154	  bool margin_negative =
155	      (DPI_SCALE(m_style.margin_x) < 0 || DPI_SCALE(m_style.margin_y) < 0);
156	  // when to hide_cadidates?
157	  // 1. margin_negative, and not in show tips mode( ascii switching / half-full
158	  // switching / simp-trad switching / error tips), and not in schema menu
159	  // 2. inline preedit without candidates
160	  bool inline_no_candidates =
161	      (m_style.inline_preedit && m_candidateCount == 0) && !show_tips;
162	  hide_candidates = inline_no_candidates ||
163	                    (margin_negative && !show_tips && !show_schema_menu);
164	
165	  // only RedrawWindow if no need to hide candidates window, or
166	  // inline_no_candidates
167	  if (!hide_candidates || inline_no_candidates) {
168	    _InitFontRes();
169	    _CreateLayout();
170	
171	    CDCHandle dc = GetDC();
172	    m_layout->DoLayout(dc, pDWR);
173	    ReleaseDC(dc);
174	    _ResizeWindow();
175	    _RepositionWindow();
176	    if (m_ctx != m_octx) {
177	      m_octx = m_ctx;
178	      RedrawWindow();
179	    }
180	  }
181	}
182	
183	void WeaselPanel::_InitFontRes(bool forced) {
184	  HMONITOR hMonitor = MonitorFromRect(m_inputPos, MONITOR_DEFAULTTONEAREST);
185	  UINT dpiX = 96, dpiY = 96;
186	  if (hMonitor)
187	    GetDpiForMonitor(hMonitor, MDT_EFFECTIVE_DPI, &dpiX, &dpiY);
188	  // prepare d2d1 resources
189	  // if style changed, or dpi changed, or pDWR NULL, re-initialize directwrite
190	  // resources
191	  if (forced || (pDWR == NULL) || (m_ostyle != m_style) || (dpiX != dpi)) {
192	    pDWR.reset();
193	    pDWR = std::make_shared<DirectWriteResources>(m_style, dpiX);
194	    pDWR->pRenderTarget->SetTextAntialiasMode(
195	        (D2D1_TEXT_ANTIALIAS_MODE)m_style.antialias_mode);
196	  }
197	  m_ostyle = m_style;
198	  dpi = dpiX;
199	  dpiScaleLayout = (float)dpi / 96.0f;
200	}
201	
202	static HBITMAP CopyDCToBitmap(HDC hDC, LPRECT lpRect) {
203	  if (!hDC || !lpRect || IsRectEmpty(lpRect))
204	    return NULL;
205	  HDC hMemDC = NULL;
206	  HBITMAP hBitmap = NULL, hOldBitmap = NULL;
207	  int nX, nY, nX2, nY2;
208	  int nWidth, nHeight;
209	
210	  nX = lpRect->left;
211	  nY = lpRect->top;
212	  nX2 = lpRect->right;
213	  nY2 = lpRect->bottom;
214	  nWidth = nX2 - nX;
215	  nHeight = nY2 - nY;
216	
217	  hMemDC = CreateCompatibleDC(hDC);
218	  if (!hMemDC)
219	    return NULL;
220	
221	  hBitmap = CreateCompatibleBitmap(hDC, nWidth, nHeight);
222	  if (!hBitmap) {
223	    DeleteDC(hMemDC);
224	    return NULL;
225	  }
226	
227	  hOldBitmap = (HBITMAP)SelectObject(hMemDC, hBitmap);
228	  if (!hOldBitmap) {
229	    DeleteObject(hBitmap);
230	    DeleteDC(hMemDC);
231	    return NULL;
232	  }
233	
234	  if (!BitBlt(hMemDC, 0, 0, nWidth, nHeight, hDC, nX, nY, SRCCOPY)) {
235	    // restore and cleanup
236	    SelectObject(hMemDC, hOldBitmap);
237	    DeleteObject(hBitmap);
238	    DeleteDC(hMemDC);
239	    return NULL;
240	  }
241	
242	  SelectObject(hMemDC, hOldBitmap);
243	  DeleteDC(hMemDC);
244	  return hBitmap;
245	}
246	
247	void WeaselPanel::_CaptureRect(CRect& rect) {
248	  HDC ScreenDC = ::GetDC(NULL);
249	  CRect rc;
250	  GetWindowRect(&rc);
251	  POINT WindowPosAtScreen = {rc.left, rc.top};
252	  CRect captureRect = rect;
253	  captureRect.OffsetRect(WindowPosAtScreen);
254	  // create bitmap first (avoid holding clipboard while capturing)
255	  HBITMAP bmp = CopyDCToBitmap(ScreenDC, LPRECT(captureRect));
256	  if (!bmp) {
257	    ::ReleaseDC(NULL, ScreenDC);
258	    return;
259	  }
260	
261	  // capture input window to clipboard
262	  if (!OpenClipboard()) {
263	    DEBUG << "_CaptureRect: OpenClipord ailed";
264	    DeleteObject(bmp);
265	    ::ReleaseDC(NULL, ScreenDC);
266	    return;
267	  }
268	  EmptyClipboard();
269	  if (!SetClipboardData(CF_BITMAP, bmp)) {
270	    DEBUG << "_CaptureRect: SetClipboardData failed";
271	    DeleteObject(bmp);
272	  }
273	  CloseClipboard();
274	  ::ReleaseDC(NULL, ScreenDC);
275	}
