312	  ptimer = 0;
313	  {
314	    // select by click
315	    CRect rect = m_layout->GetCandidateRect((int)m_ctx.cinfo.highlighted);
316	    if (m_istorepos)
317	      rect.OffsetRect(0, m_offsetys[m_ctx.cinfo.highlighted]);
