463	LRESULT WeaselPanel::OnMouseMove(UINT uMsg,
464	                                 WPARAM wParam,
465	                                 LPARAM lParam,
466	                                 BOOL& bHandled) {
467	  if (m_style.hover_type == UIStyle::NONE)
468	    return 0;
469	  if (m_mouse_entry == false) {
470	    TRACKMOUSEEVENT tme;
471	    tme.cbSize = sizeof(TRACKMOUSEEVENT);
472	    tme.dwFlags = TME_LEAVE;
473	    tme.dwHoverTime = 20;  // unit: ms
474	    tme.hwndTrack = m_hWnd;
475	    TrackMouseEvent(&tme);
476	  }
477	  bHandled = true;
478	  m_mouse_entry = true;
479	  CPoint point;
480	  point.x = GET_X_LPARAM(lParam);
481	  point.y = GET_Y_LPARAM(lParam);
482	
483	  // Ignore if mouse screen position not changed
484	  CPoint ptScreen = point;
485	  ClientToScreen(&ptScreen);
486	  if (ptScreen == m_lastMousePos || m_lastMousePos.x == -1) {
487	    if (m_lastMousePos.x == -1)
488	      m_lastMousePos = ptScreen;
489	    return 0;
490	  }
491	  m_lastMousePos = ptScreen;
492	
493	  for (size_t i = 0; i < m_candidateCount && i < MAX_CANDIDATES_COUNT; ++i) {
494	    CRect rect = m_layout->GetCandidateRect((int)i);
495	    if (m_istorepos)
496	      rect.OffsetRect(0, m_offsetys[i]);
497	    rect.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
498	                     DPI_SCALE(m_style.hilite_padding_y));
499	    if (rect.PtInRect(point)) {
500	      if (i != m_ctx.cinfo.highlighted) {
501	        if (m_style.hover_type == UIStyle::HoverType::HILITE) {
502	          if (_UICallback)
503	            _UICallback(NULL, &i, NULL, NULL);
504	        } else if (m_hoverIndex != i) {
505	          m_hoverIndex = static_cast<int>(i);
506	          InvalidateRect(&rcw, true);
507	        }
508	      } else if (m_style.hover_type == UIStyle::HoverType::SEMI_HILITE &&
509	                 m_hoverIndex != -1) {
510	        m_hoverIndex = -1;
511	        InvalidateRect(&rcw, true);
512	      }
513	    }
514	  }
515	  return 0;
516	}
