528	void WeaselPanel::_HighlightText(CDCHandle& dc,
529	                                 const CRect& rc,
530	                                 const COLORREF& color,
531	                                 const COLORREF& shadowColor,
532	                                 const int& radius,
533	                                 const BackType& type = BackType::TEXT,
534	                                 const IsToRoundStruct& rd = IsToRoundStruct(),
535	                                 const COLORREF& bordercolor = TRANS_COLOR) {
536	  // Graphics obj with SmoothingMode
537	  Gdiplus::Graphics g_back(dc);
538	  g_back.SetSmoothingMode(Gdiplus::SmoothingMode::SmoothingModeHighQuality);
539	
540	  // blur buffer
541	  int blurMarginX = m_layout->offsetX;
542	  int blurMarginY = m_layout->offsetY;
543	
544	  GraphicsRoundRectPath* hiliteBackPath;
545	  if (rd.Hemispherical && type != BackType::BACKGROUND &&
546	      NOT_FULLSCREENLAYOUT(m_style))
547	    hiliteBackPath = new GraphicsRoundRectPath(
548	        rc,
549	        DPI_SCALE(m_style.round_corner_ex) -
550	            (DPI_SCALE(m_style.border) % 2 ? DPI_SCALE(m_style.border) / 2 : 0),
551	        rd.IsTopLeftNeedToRound, rd.IsTopRightNeedToRound,
552	        rd.IsBottomRightNeedToRound, rd.IsBottomLeftNeedToRound);
553	  else  // background or current candidate background not out of window
554	        // background
555	    hiliteBackPath = new GraphicsRoundRectPath(rc, radius);
556	
557	  // 必须shadow_color都是非完全透明色才做绘制, 全屏状态不绘制阴影保证响应速度
558	  if (DPI_SCALE(m_style.shadow_radius) && COLORNOTTRANSPARENT(shadowColor) &&
559	      NOT_FULLSCREENLAYOUT(m_style)) {
560	    CRect rect(blurMarginX + DPI_SCALE(m_style.shadow_offset_x),
561	               blurMarginY + DPI_SCALE(m_style.shadow_offset_y),
562	               rc.Width() + blurMarginX + DPI_SCALE(m_style.shadow_offset_x),
563	               rc.Height() + blurMarginY + DPI_SCALE(m_style.shadow_offset_y));
564	    BYTE r = GetRValue(shadowColor);
565	    BYTE g = GetGValue(shadowColor);
566	    BYTE b = GetBValue(shadowColor);
567	    BYTE alpha = (BYTE)((shadowColor >> 24) & 255);
568	    Gdiplus::Color shadow_color = Gdiplus::Color::MakeARGB(alpha, r, g, b);
569	    static Gdiplus::Bitmap* pBitmapDropShadow;
570	    pBitmapDropShadow = new Gdiplus::Bitmap((INT)rc.Width() + blurMarginX * 2,
571	                                            (INT)rc.Height() + blurMarginY * 2,
572	                                            PixelFormat32bppPARGB);
573	
574	    Gdiplus::Graphics g_shadow(pBitmapDropShadow);
575	    g_shadow.SetSmoothingMode(Gdiplus::SmoothingModeHighQuality);
576	    // dropshadow, draw a roundrectangle to blur
577	    if (DPI_SCALE(m_style.shadow_offset_x) != 0 ||
578	        DPI_SCALE(m_style.shadow_offset_y) != 0) {
579	      GraphicsRoundRectPath shadow_path(rect, radius);
580	      Gdiplus::SolidBrush shadow_brush(shadow_color);
581	      g_shadow.FillPath(&shadow_brush, &shadow_path);
582	    }
583	    // round shadow, draw multilines as base round line
584	    else {
585	      int step = alpha / DPI_SCALE(m_style.shadow_radius) / 2;
586	      Gdiplus::Pen pen_shadow(shadow_color, (Gdiplus::REAL)1);
587	      for (int i = 0; i < DPI_SCALE(m_style.shadow_radius); i++) {
588	        GraphicsRoundRectPath round_path(rect, radius + 1 + i);
589	        g_shadow.DrawPath(&pen_shadow, &round_path);
590	        shadow_color = Gdiplus::Color::MakeARGB(alpha - i * step, r, g, b);
591	        pen_shadow.SetColor(shadow_color);
592	        rect.InflateRect(1, 1);
593	      }
594	    }
595	    DoGaussianBlur(pBitmapDropShadow, (float)DPI_SCALE(m_style.shadow_radius),
596	                   (float)DPI_SCALE(m_style.shadow_radius));
597	
598	    g_back.DrawImage(pBitmapDropShadow, rc.left - blurMarginX,
599	                     rc.top - blurMarginY);
600	
601	    // free memory
602	    delete pBitmapDropShadow;
603	    pBitmapDropShadow = NULL;
604	  }
605	
606	  // 必须back_color非完全透明才绘制
607	  if (COLORNOTTRANSPARENT(color)) {
608	    Gdiplus::Color back_color = GDPCOLOR_FROM_COLORREF(color);
609	    Gdiplus::SolidBrush back_brush(back_color);
610	    g_back.FillPath(&back_brush, hiliteBackPath);
611	  }
612	  // draw border, for bordercolor not transparent and border valid
613	  if (COLORNOTTRANSPARENT(bordercolor) && DPI_SCALE(m_style.border) > 0) {
614	    Gdiplus::Color border_color = GDPCOLOR_FROM_COLORREF(bordercolor);
615	    Gdiplus::Pen gPenBorder(border_color,
616	                            (Gdiplus::REAL)DPI_SCALE(m_style.border));
617	    // candidate window border
618	    if (type == BackType::BACKGROUND) {
619	      GraphicsRoundRectPath bgPath(rc, DPI_SCALE(m_style.round_corner_ex));
620	      g_back.DrawPath(&gPenBorder, &bgPath);
621	    } else if (type !=
622	               BackType::TEXT)  // hilited_candidate_border / candidate_border
623	      g_back.DrawPath(&gPenBorder, hiliteBackPath);
624	  }
625	  // free memory
626	  delete hiliteBackPath;
627	  hiliteBackPath = NULL;
628	}
