1172	void WeaselPanel::MoveTo(RECT const& rc) {
1173	  if (!m_layout)
1174	    return;  // avoid handling nullptr in _RepositionWindow
1175	  m_redraw_by_monitor_change = false;
1176	  // The conditions for resetting the sticky state:
1177	  // 1. When the input session ends (ctx.empty() is true)
1178	  // 2. When the input position changes significantly (the position change
1179	  // exceeds the threshold)
1180	  // 3. When the content of the candidate window is empty
1181	  bool should_reset_sticky =
1182	      (m_ctx.empty() || (abs(rc.left - m_inputPos.left) > 50) ||
1183	       (abs(rc.bottom - m_inputPos.bottom) > 50));
1184	  if (should_reset_sticky && m_sticky) {
1185	    m_sticky = false;
1186	    // Force reposition the window
1187	    m_inputPos = rc;
1188	    m_inputPos.OffsetRect(0, 6);
1189	    _RepositionWindow(true);
1190	    RedrawWindow();
1191	    return;
1192	  }
1193	  // if ascii_tip_follow_cursor set, move tip icon to mouse cursor
1194	  if (m_style.ascii_tip_follow_cursor && m_ctx.empty() &&
1195	      (!m_status.composing) && m_layout->ShouldDisplayStatusIcon()) {
1196	    // ascii icon follow cursor
1197	    POINT p;
1198	    ::GetCursorPos(&p);
1199	    RECT irc{p.x - STATUS_ICON_SIZE, p.y - STATUS_ICON_SIZE, p.x, p.y};
1200	    m_inputPos = irc;
1201	    _RepositionWindow(true);
1202	    RedrawWindow();
1203	  } else if (!(rc.left == m_inputPos.left && rc.bottom != m_inputPos.bottom &&
1204	               abs(rc.bottom - m_inputPos.bottom) < 6) ||
1205	             m_layout->ShouldDisplayStatusIcon()) {
1206	    // in some apps like word 2021, with inline_preedit set,
1207	    // bottom of rc would flicker 1 px or 2, make the candidate flickering
1208	    m_inputPos = rc;
1209	    m_inputPos.OffsetRect(0, 6);
1210	    // buffer current m_istorepos status
1211	    bool m_istorepos_buf = m_istorepos;
1212	    // with parameter to avoid vertical flicker
1213	    _RepositionWindow(true);
1214	    // m_istorepos status changed by _RepositionWindow, or tips to show,
1215	    // redrawing is required
1216	    if (m_istorepos != m_istorepos_buf || !m_ctx.aux.empty() ||
1217	        m_layout->ShouldDisplayStatusIcon() || m_redraw_by_monitor_change)
1218	      RedrawWindow();
1219	  }
1220	}
1221	
1222	void WeaselPanel::_RepositionWindow(const bool& adj) {
1223	  RECT rcWorkArea;
1224	  memset(&rcWorkArea, 0, sizeof(rcWorkArea));
1225	  HMONITOR hMonitor = MonitorFromRect(m_inputPos, MONITOR_DEFAULTTONEAREST);
1226	  if (hMonitor) {
1227	    MONITORINFO info;
1228	    info.cbSize = sizeof(MONITORINFO);
1229	    if (GetMonitorInfo(hMonitor, &info)) {
1230	      rcWorkArea = info.rcWork;
1231	    }
1232	    if (hMonitor != m_hMonitor) {
1233	      m_hMonitor = hMonitor;
1234	      m_redraw_by_monitor_change = true;
1235	    }
1236	  }
1237	  RECT rcWindow;
1238	  GetWindowRect(&rcWindow);
1239	  int width = (rcWindow.right - rcWindow.left);
1240	  int height = (rcWindow.bottom - rcWindow.top);
1241	  // keep panel visible
1242	  rcWorkArea.right -= width;
1243	  rcWorkArea.bottom -= height;
1244	  int x = m_inputPos.left;
1245	  int y = m_inputPos.bottom;
1246	  if (DPI_SCALE(m_style.shadow_radius)) {
1247	    x -= (DPI_SCALE(m_style.shadow_offset_x) >= 0 ||
1248	          COLORTRANSPARENT(m_style.shadow_color))
1249	             ? m_layout->offsetX
1250	             : (m_layout->offsetX / 2);
1251	    if (adj)
1252	      y -= (DPI_SCALE(m_style.shadow_offset_y) > 0 ||
1253	            COLORTRANSPARENT(m_style.shadow_color))
1254	               ? m_layout->offsetY
1255	               : (m_layout->offsetY / 2);
1256	  }
1257	  // for vertical text layout, flow right to left, make window left side
1258	  if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT &&
1259	      !m_style.vertical_text_left_to_right) {
