1265	    m_istorepos = false;
1266	  if (x > rcWorkArea.right)
1267	    x = rcWorkArea.right;  // over workarea right
1268	  if (x < rcWorkArea.left)
1269	    x = rcWorkArea.left;  // over workarea left
1270	  // show panel above the input focus if we're around the bottom
1271	  if (y > rcWorkArea.bottom || m_sticky) {
1272	    if (!m_sticky)
1273	      m_sticky = true;
1274	    y = m_inputPos.top - height - 6;  // over workarea bottom
1275	    if (DPI_SCALE(m_style.shadow_radius) &&
1276	        DPI_SCALE(m_style.shadow_offset_y) > 0)
1277	      y -= DPI_SCALE(m_style.shadow_offset_y);
1278	    m_istorepos = (m_style.vertical_auto_reverse &&
1279	                   m_style.layout_type == UIStyle::LAYOUT_VERTICAL);
1280	    if (DPI_SCALE(m_style.shadow_radius) > 0)
